<style>.panel-dmt .panel-dark-icon-sun{display:none}.panel-dmt .panel-dark-icon-moon{display:inline-flex}html[data-theme="dark"] .panel-dmt .panel-dark-icon-moon{display:none}html[data-theme="dark"] .panel-dmt .panel-dark-icon-sun{display:inline-flex}html[data-theme="dark"] .panel-dmt-btn{border-color:var(--panel-card-border,#334155);color:var(--panel-text-primary,#e2e8f0)}</style>
<span class="panel-dmt">
    <button type="button" class="panel-dmt-btn" onclick="togglePanelDarkModeStandalone()" style="display:inline-flex;align-items:center;gap:4px;background:none;border:1px solid var(--panel-card-border,#e2e8f0);border-radius:6px;padding:5px 10px;cursor:pointer;font-size:.8rem;font-weight:600;color:var(--panel-text-primary,#334155)" title="{{ __('panel::messages.toggle_dark_mode') }}">
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" width="16" height="16" class="panel-dark-icon-moon"><path stroke-linecap="round" stroke-linejoin="round" d="M21.752 15.002A9.72 9.72 0 0 1 18 15.75c-5.385 0-9.75-4.365-9.75-9.75 0-1.33.266-2.597.748-3.752A9.753 9.753 0 0 0 3 11.25C3 16.635 7.365 21 12.75 21a9.753 9.753 0 0 0 8.002-4.248Z"/></svg>
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor" width="16" height="16" class="panel-dark-icon-sun"><path stroke-linecap="round" stroke-linejoin="round" d="M12 3v2.25m6.364.386-1.591 1.591M21 12h-2.25m-.386 6.364-1.591-1.591M12 18.75V21m-4.773-4.227-1.591 1.591M5.25 12H3m4.227-4.773L5.636 5.636M15.75 12a3.75 3.75 0 1 1-7.5 0 3.75 3.75 0 0 1 7.5 0Z"/></svg>
    </button>
</span>
<script>
function togglePanelDarkModeStandalone(){var h=document.documentElement,a=h.getAttribute('data-theme')!=='dark';if(a){h.setAttribute('data-theme','dark');h.setAttribute('data-bs-theme','dark');localStorage.setItem('panel-dark-mode','true')}else{h.removeAttribute('data-theme');h.removeAttribute('data-bs-theme');localStorage.setItem('panel-dark-mode','false')}window.dispatchEvent(new CustomEvent('panel:dark-mode',{detail:{active:a}}))}
</script>
